1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	};
9	
10	type Item = { type: string };
11	type Step = { op: string; items: Item[] };
12	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
13	
14	const itemBasePremium = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
15	
16	const quoteStep = (step: Step): { premium: number } => {
17	  const base = step.items.reduce((sum, item) => sum + itemBasePremium(item), 0);
18	  const firstInsurance = base * FIRST_INSURANCE_RATE;
19	  return { premium: base + firstInsurance + PROCESSING_FEE };
20	};
21	
22	export const runScenario = (scenario: unknown): unknown => {
23	  const { steps } = scenario as Scenario;
24	  return { results: steps.map(quoteStep) };
25	};
